sql:
SELECT author_id, COUNT(book_id) AS num_books
FROM books
GROUP BY author_id;

external_knowledge:
- The term "reviews" refers to ratings given by users;
- "Overall average rating" means the average of all ratings for a book;
- "Most highly rated books first" indicates sorting by decreasing average ratings.

sql:
SELECT title, publication_date
FROM books
ORDER BY publication_date DESC;

SELECT AVG(r.rating) AS average_rating
FROM awards a
INNER JOIN ratings r ON a.book_id = r.book_id;

SELECT book_id, COUNT(award_id) AS num_awards
FROM awards
GROUP BY book_id;

SELECT AVG(num_reviews) AS average_reviews_per_year,
       AVG(CASE WHEN book_id = 1 THEN num_reviews ELSE 0 END) AS specific_book_reviews_per_year
FROM reviews_per_year;

SELECT AVG(num_reviews) AS average_reviews_per_year
FROM reviews_per_year
WHERE year BETWEEN (strftime('%Y', 'now') - 10) AND strftime('%Y', 'now');

SELECT AVG(rating) AS average_rating
FROM ratings
JOIN recommendations ON ratings.book_id = recommendations.book_id;

SELECT books.title, authors.author_name
FROM books
JOIN authors ON books.author_id = authors.author_id;

SELECT title, author_id, publisher_id, publication_date, format_id, isbn, pages
FROM books
WHERE book_id = 1;

SELECT title
FROM books
WHERE publication_date LIKE '2020%';

SELECT AVG(rating) AS average_rating
FROM ratings
WHERE user_id = 1;

external_knowledge:
Average rating: the mean score given by users on a scale, typically between 1 and 5 stars;
Favorite count: how many times a book is marked as a favorite by users;
Award count: the total number of awards a book has received;
Top 10: the first ten books in the ranked list based on the combined criteria.

sql:
SELECT b.title
FROM books b
INNER JOIN favorite_books fb ON b.book_id = fb.book_id;
